import{_ as t,o as r,c as o,ag as e}from"./chunks/framework.C9sp7nFj.js";const m=JSON.parse('{"title":"邮件","description":"","frontmatter":{},"headers":[],"relativePath":"zh/getting-started/email.md","filePath":"zh/getting-started/email.md","lastUpdated":1777012567000}'),i={name:"zh/getting-started/email.md"};function l(n,a,s,d,h,g){return r(),o("div",null,[...a[0]||(a[0]=[e('<h1 id="邮件" tabindex="-1">邮件 <a class="header-anchor" href="#邮件" aria-label="Permalink to &quot;邮件&quot;">​</a></h1><p>让机器人<strong>收/发</strong>邮件，分两步：<strong>邮服提供方</strong> + 机器人上的 <strong>Email 绑定</strong>。</p><h2 id="在做什么" tabindex="-1">在做什么 <a class="header-anchor" href="#在做什么" aria-label="Permalink to &quot;在做什么&quot;">​</a></h2><ol><li>先配能连上的 <strong>Email Provider</strong>（如 Mailgun、泛用 SMTP 等）。</li><li>再在某个机器人上，把某邮箱<strong>绑定</strong>过去，并设读/写/删权限。</li></ol><hr><h2 id="邮服" tabindex="-1">邮服 <a class="header-anchor" href="#邮服" aria-label="Permalink to &quot;邮服&quot;">​</a></h2><p>侧栏 <strong>Email Provider</strong>。</p><h3 id="新建" tabindex="-1">新建 <a class="header-anchor" href="#新建" aria-label="Permalink to &quot;新建&quot;">​</a></h3><ol><li><strong>Add Email Provider</strong></li><li>类型如 <strong>Mailgun</strong>（量大）、<strong>泛用 SMTP</strong>（传统邮局）</li><li>按表单填 <code>domain</code>/<code>api_key</code> 或 <code>host</code>/<code>port</code> 等</li><li>创建</li></ol><hr><h2 id="机器人上的绑定" tabindex="-1">机器人上的绑定 <a class="header-anchor" href="#机器人上的绑定" aria-label="Permalink to &quot;机器人上的绑定&quot;">​</a></h2><p>机器人 <strong>Email</strong> tab。</p><h3 id="添加" tabindex="-1">添加 <a class="header-anchor" href="#添加" aria-label="Permalink to &quot;添加&quot;">​</a></h3><ol><li><strong>Add Binding</strong></li><li>选已建的 <strong>Email Provider</strong></li><li>填要绑的 <strong>Email Address</strong></li><li>勾权限： <ul><li><strong>Can Read</strong> 收信、处理入站</li><li><strong>Can Write</strong> 发信</li><li><strong>Can Delete</strong> 管邮箱里删除等（视实现）</li></ul></li><li>创建</li></ol><h3 id="发件箱" tabindex="-1">发件箱 <a class="header-anchor" href="#发件箱" aria-label="Permalink to &quot;发件箱&quot;">​</a></h3><p><strong>Outbox</strong> 会记发出的邮件：收信人、主题、状态、时间，便于对账、排错。</p><hr><h2 id="和机器人" tabindex="-1">和机器人 <a class="header-anchor" href="#和机器人" aria-label="Permalink to &quot;和机器人&quot;">​</a></h2><ul><li>有权限时可用邮件发报告、回邮、或按新邮件做事。</li><li>和聊天一样，是另一条通道，但仍是结构化、可审的。</li></ul>',19)])])}const u=t(i,[["render",l]]);export{m as __pageData,u as default};
